177	  constexpr DispatchKeySet(Full /*unused*/)
178	      : repr_((1ULL << (num_backends + num_functionality_keys - 1)) - 1) {}
179	
180	  constexpr DispatchKeySet(FullAfter /*unused*/, DispatchKey t)
181	      // LSB after t are OK, but not t itself.
182	      // "functionalities" have a notion of ordering (e.g. Autograd > Sparse >
183	      // Quantized > Dense). But backends don't really have an ordering.
184	      // Therefore, we're enforcing that FullAfter can only be used on
185	      // "functionality" keys.
186	      : repr_(
187	            (1ULL
188	             << (num_backends + static_cast<uint8_t>(toFunctionalityKey(t)) -
189	                 1)) -
190	            1) {
191	    *this = add(DispatchKey::PythonDispatcher);
192	  }
193	
194	  // Public version of DispatchKeySet(uint64_t) API; external users
195	  // must be explicit when they do this!
196	  constexpr DispatchKeySet(Raw /*unused*/, uint64_t x) : repr_(x) {}
197	
198	  constexpr explicit DispatchKeySet(BackendComponent k) {
199	    if (k == BackendComponent::InvalidBit) {
200	      repr_ = 0;
201	    } else {
202	      repr_ = 1ULL << (static_cast<uint8_t>(k) - 1);
203	    }
204	  }
