206	  constexpr explicit DispatchKeySet(DispatchKey k) {
207	    // NOLINTNEXTLINE(bugprone-branch-clone)
208	    if (k == DispatchKey::Undefined) {
209	      // Case 1: handle Undefined specifically
210	      repr_ = 0;
211	    } else if (k <= DispatchKey::EndOfFunctionalityKeys) {
212	      // Case 2: handle "functionality-only" keys
213	      // These keys have a functionality bit set, but no backend bits
214	      // These can technically be either:
215	      // - valid runtime keys (e.g. DispatchKey::AutogradOther,
216	      // DispatchKey::FuncTorchBatched, etc)
217	      // - "building block" keys that aren't actual runtime keys (e.g.
218	      // DispatchKey::Dense or Sparse)
219	      uint64_t functionality_val = 1ULL
220	          << (num_backends + static_cast<uint8_t>(k) - 1);
221	      repr_ = functionality_val;
222	    } else if (k <= DispatchKey::EndOfRuntimeBackendKeys) {
223	      // Case 3: "runtime" keys that have a functionality bit AND a backend bit.
224	      // First compute which bit to flip for the functionality.
225	      auto functionality_k = toFunctionalityKey(k);
226	      // The - 1 is because Undefined is technically a "functionality" that
227	      // doesn't show up in the bitset. So e.g. Dense is technically the second
228	      // functionality, but the lowest functionality bit.
229	      uint64_t functionality_val = 1ULL
230	          << (num_backends + static_cast<uint8_t>(functionality_k) - 1);
231	
232	      // then compute which bit to flip for the backend
233	      // Case 4a: handle the runtime instances of "per-backend functionality"
234	      // keys For example, given DispatchKey::CPU, we should set:
235	      // - the Dense functionality bit
236	      // - the CPUBit backend bit
237	      // first compute which bit to flip for the backend
238	      auto backend_k = toBackendComponent(k);
239	      uint64_t backend_val = backend_k == BackendComponent::InvalidBit
240	          ? 0
241	          : 1ULL << (static_cast<uint8_t>(backend_k) - 1);
242	      repr_ = functionality_val + backend_val;
243	    } else {
244	      // At this point, we should have covered every case except for alias keys.
245	      // Technically it would be possible to add alias dispatch keys to a
246	      // DispatchKeySet, but the semantics are a little confusing and this
247	      // currently isn't needed anywhere.
248	      repr_ = 0;
249	    }
250	  }
