252	  constexpr uint64_t keys_to_repr(std::initializer_list<DispatchKey> ks) {
253	    uint64_t repr = 0;
254	    for (auto k : ks) {
255	      repr |= DispatchKeySet(k).repr_;
256	    }
257	    return repr;
258	  }
259	
260	  constexpr uint64_t backend_bits_to_repr(
261	      std::initializer_list<BackendComponent> ks) {
262	    uint64_t repr = 0;
263	    for (auto k : ks) {
264	      repr |= DispatchKeySet(k).repr_;
265	    }
266	    return repr;
267	  }
