269	  explicit constexpr DispatchKeySet(std::initializer_list<DispatchKey> ks)
270	      : repr_(keys_to_repr(ks)) {}
271	
272	  explicit constexpr DispatchKeySet(std::initializer_list<BackendComponent> ks)
273	      : repr_(backend_bits_to_repr(ks)) {}
