275	  // Test if a DispatchKey is in the set
276	  [[nodiscard]] inline bool has(DispatchKey t) const {
277	    TORCH_INTERNAL_ASSERT_DEBUG_ONLY(t != DispatchKey::Undefined);
278	    return has_all(DispatchKeySet(t));
279	  }
280	  [[nodiscard]] constexpr bool has_backend(BackendComponent t) const {
281	    return has_all(DispatchKeySet(t));
282	  }
