284	  // Test if a DispatchKey is in the set
285	  // Given a DispatchKeySet of functionality keys and (potentially) backend
286	  // keys, tests if all of them are in the current set.
287	  [[nodiscard]] constexpr bool has_all(DispatchKeySet ks) const {
288	    return static_cast<bool>((repr_ & ks.repr_) == ks.repr_);
289	  }
