316	  }
317	  // Test if DispatchKeySet is a superset of ks.
318	  [[nodiscard]] bool isSupersetOf(DispatchKeySet ks) const {
319	    return (repr_ & ks.repr_) == ks.repr_;
320	  }
321	  // Perform set union
322	  constexpr DispatchKeySet operator|(DispatchKeySet other) const {
323	    return DispatchKeySet(repr_ | other.repr_);
324	  }
325	  // Perform set intersection
326	  constexpr DispatchKeySet operator&(DispatchKeySet other) const {
327	    return DispatchKeySet(repr_ & other.repr_);
328	  }
329	  // Compute the set difference self - other,
330	  // but ONLY for the functionality keys.
331	  // Any backend bits set on self will remain unchanged.
332	  // See Note [Removing keys from DispatchKeySet Only Affects Functionality
333	  // Keys]
