338	  // Compute self ^ other
339	  constexpr DispatchKeySet operator^(DispatchKeySet other) const {
340	    return DispatchKeySet(repr_ ^ other.repr_);
341	  }
342	  bool operator==(DispatchKeySet other) const {
343	    return repr_ == other.repr_;
344	  }
345	  bool operator!=(DispatchKeySet other) const {
346	    return repr_ != other.repr_;
347	  }
348	  // Add a DispatchKey to the DispatchKey set.  Does NOT mutate,
349	  // returns the extended DispatchKeySet!
350	  [[nodiscard]] constexpr DispatchKeySet add(DispatchKey t) const {
351	    return *this | DispatchKeySet(t);
352	  }
353	  [[nodiscard]] constexpr DispatchKeySet add(DispatchKeySet ks) const {
354	    return *this | ks;
355	  }
