357	  // Remove a DispatchKey from the DispatchKey set.
358	  // This is generally not an operation you should be doing
359	  // (it's used to implement the printing overload, operator<<)
360	  //
361	  // Note [Removing keys from DispatchKeySet Only Affects Functionality Keys]
362	  // Only functionality bits are allowed to be removed from a keyset.
363	  // For now, we're only allowing removal of "functionality bits" from the
364	  // keyset, which is specifically needed by the fallthrough key calculation
365	  // logic. Why is removing backend bits problematic? Consider this example:
366	  //
367	  // DispatchKeySet([DispatchKey.CPU, DispatchKey.AutogradCUDA,
368	  // DispatchKey.CUDA]).remove(DispatchKey.AutogradCUDA)
369	  // DispatchKeySet([DispatchKey.CPU,
370	  // DispatchKey.AutogradCUDA]).remove(DispatchKey.AutogradCUDA)
371	  //
372	  // What do we want to happen?
373	  // Technically, we'd like it to be true that after removal,
374	  // the first keyset still has the CUDA dispatch key while the second doesn't.
375	  // Unfortunately there's no way to represent that, because the two keysets are
376	  // represented the same way internally: functionality bits: Autograd, Dense
377	  // backend bits: CPU, CUDA
378	  //
379	  // Instead, remove(DispatchKey.AutogradCPU) will only remove the "Autograd"
380	  // bit from the bitset.
381	  [[nodiscard]] constexpr DispatchKeySet remove(DispatchKey t) const {
382	    return DispatchKeySet(
383	        repr_ & ~(DispatchKeySet(t).repr_ & ~full_backend_mask));
384	  }
385	  // You're allowed to remove a backend bit from a DispatchKeySet,
386	  // but you have to be explicit about it (remove_backend() instead of
387	  // remove()).
388	  constexpr DispatchKeySet remove_backend(BackendComponent b) const {
389	    return DispatchKeySet(repr_ & ~(DispatchKeySet(b).repr_));
390	  }
391	  // Is the set empty?  (AKA undefined tensor)
392	  [[nodiscard]] bool empty() const {
393	    return repr_ == 0;
394	  }
395	  [[nodiscard]] uint64_t raw_repr() const {
396	    return repr_;
397	  }
