403	  [[nodiscard]] DispatchKey highestFunctionalityKey() const {
404	    auto functionality_idx = indexOfHighestBit();
405	    // This means that none of the functionality bits were set.
406	    if (functionality_idx < num_backends)
407	      return DispatchKey::Undefined;
408	    // The first num_backend bits in the keyset don't correspond to real
409	    // dispatch keys.
410	    return static_cast<DispatchKey>(functionality_idx - num_backends);
411	  }
412	
413	  // This is similar like toBackendComponent(DispatchKey), but less restrictive.
414	  // toBackendComponent() errors out if the key that it was passed has no
415	  // backend bits, which is useful for error checking. We need a version of that
416	  // here that can also handle "fake" backends like FPGA, because they need to
417	  // map to the AutogradOther key. For those backends, we return
418	  // BackendComponent::InvalidBit.
419	  [[nodiscard]] BackendComponent highestBackendKey() const {
420	    // mask to mask out functionality bits
421	    auto backend_idx =
422	        DispatchKeySet(repr_ & full_backend_mask).indexOfHighestBit();
423	    // all zeros across the backend bits means that no backend bits are set.
424	    if (backend_idx == 0)
425	      return BackendComponent::InvalidBit;
426	    return static_cast<BackendComponent>(backend_idx);
427	  }
