431	    auto functionality_k = highestFunctionalityKey();
432	    if (isPerBackendFunctionalityKey(functionality_k)) {
433	      return toRuntimePerBackendFunctionalityKey(
434	          functionality_k, highestBackendKey());
435	    }
436	    return functionality_k;
437	  }
