439	  // Returns the index of the most-significant bit in the keyset.
440	  // This is used to as part of the calculation into the operator table to get:
441	  // - the highest "functionality" bit in the keyset.
442	  // - the highest "backend" bit in the keyset.
443	  [[nodiscard]] uint8_t indexOfHighestBit() const {
444	    return 64 - llvm::countLeadingZeros(repr_);
445	  }
