447	#if defined(C10_MOBILE_TRIM_DISPATCH_KEYS)
448	  // [Note: Trimmed Mobile Dispatch Keys]
449	  /**
450	   * The method below maps the dispatch key in the enum DispatchKey to an
451	   * integer index in the dispatchTable_ array in OperatorEntry. The array
452	   * is trimmed for mobile to reduce peak memory usage since it's
453	   * unnecessary to reserve additional space for dispatch keys that will
454	   * never be used on mobile.
455	   */
456	  [[nodiscard]] int getDispatchTableIndexForDispatchKeySet() const {
457	    auto dk = highestPriorityTypeId();
458	    switch (dk) {
459	      case DispatchKey::Undefined:
460	        return 0;
461	      case DispatchKey::CPU:
462	        return 1;
463	      case DispatchKey::QuantizedCPU:
464	        return 2;
465	      case DispatchKey::SparseCPU:
466	        return 3;
467	      case DispatchKey::BackendSelect:
468	        return 4;
469	      case DispatchKey::ADInplaceOrView:
470	        return 5;
471	      case DispatchKey::AutogradOther:
472	        return 6;
473	      case DispatchKey::AutogradCPU:
474	        return 7;
475	      default:
476	        return -1;
477	    }
478	  }
479	#else
480	  // returns the index in the operator table of highest priority key in the the
481	  // keyset Note that we could in theory implement this using
482	  // highestPriorityTypeId(), but this code is very hotpath and we can do it
483	  // faster without it.
484	  [[nodiscard]] int getDispatchTableIndexForDispatchKeySet() const {
485	    auto functionality_idx =
486	        DispatchKeySet(repr_ >> num_backends).indexOfHighestBit();
487	    auto offset_and_mask = offsetsAndMasks()[functionality_idx];
488	    // Mask the functionality bits out first, then right-shift by 1.
489	    // right-shifting by 1 because everything is zero-indexed.
490	    // E.g. 000001 (CPU) should give us an offset of 0, 000010 (CUDA) should
491	    // give us an offset of 1, etc.
492	    auto backend_idx =
493	        DispatchKeySet((repr_ & offset_and_mask.mask) >> 1).indexOfHighestBit();
494	    return offset_and_mask.offset + backend_idx;
495	  }
496	#endif
