498	  // returns the "index" of the highest priority backend in the keyset.
499	  // This is pretty similar to getBackendKey(), but:
500	  // - It's hotpath code (part of the runtime bitset calculation)
501	  // - I's returns an integer index, not an enum value
502	  // - Everything is shifted to the right by 1.
503	  //   BackendComponent::InvalidBit is technically the lowest enum value,
504	  //   but it isn't included in the runtime table. So CPUBit = 1, CUDABit = 2,
505	  //   etc.
506	  uint64_t getBackendIndex() const {
507	    return DispatchKeySet((repr_ & full_backend_mask) >> 1).indexOfHighestBit();
508	  }
