514	 public:
515	  // STL iterator for DispatchKeySet. Iterates through all runtime DispatchKeys
516	  // in the set. The iterator is only invalidated by the destruction of the
517	  // underlying DispatchKeySet as the iterator stores a pointer to the raw
518	  // representation of the DispatchKeySet. Note: When we encounter a per-backend
519	  // functionality (e.g. Dense or Sparse), we will iterate through EVERY backend
520	  // in the keyset, for that functionality. For example, if the next
521	  // functionality key to iterate over is Autograd, and the backend bits in the
522	  // keyset correspond to [BackendComponent::CPUBit, BackendComponent::CUDABit],
523	  // then the next two keys we return will be DispatchKey::AutogradCPU,
524	  // DispatchKey::AutogradCUDA (CPU first because it has lower precedence than
525	  // CUDA in DispatchKey.h).
526	  class iterator {
527	   public:
528	    using self_type = iterator;
529	    using iterator_category = std::input_iterator_tag;
530	    using value_type = DispatchKey;
531	    using difference_type = ptrdiff_t;
532	    using reference = value_type&;
533	    using pointer = value_type*;
534	    // final mask value should mask out the entire keyset
535	    static constexpr uint8_t end_iter_mask_val =
536	        num_backends + num_functionality_keys;
537	    // final key value should be the last DispatchKey
538	    static constexpr uint8_t end_iter_key_val = num_functionality_keys;
539	
540	    // current_dispatchkey_idx_ will iterate through all functionality bits.
541	    // current_backendcomponent_idx_ will iterate through all backend bits.
542	    explicit iterator(
543	        const uint64_t* data_ptr,
544	        uint8_t next_functionality = num_backends,
545	        uint8_t next_backend = 0)
546	        : data_ptr_(data_ptr),
547	          next_functionality_(next_functionality),
548	          next_backend_(next_backend) {
549	      // Go to the first key in the set
550	      TORCH_INTERNAL_ASSERT(
551	          next_functionality_ >= num_backends,
552	          "num_backends=",
553	          static_cast<uint32_t>(num_backends),
554	          "next_functionality_=",
555	          static_cast<uint32_t>(next_functionality_));
556	      ++(*this);
557	    }
558	
559	    C10_API self_type& operator++();
560	
561	    self_type operator++(int) {
562	      self_type previous_iterator = *this;
563	      ++(*this);
564	      return previous_iterator;
565	    }
566	
567	    bool operator==(const self_type& rhs) const {
568	      return next_functionality_ == rhs.next_functionality_ &&
569	          current_dispatchkey_idx_ == rhs.current_dispatchkey_idx_ &&
570	          next_backend_ == rhs.next_backend_ &&
571	          current_backendcomponent_idx_ == rhs.current_backendcomponent_idx_;
572	    }
573	    bool operator!=(const self_type& rhs) const {
574	      return next_functionality_ != rhs.next_functionality_ ||
575	          current_dispatchkey_idx_ != rhs.current_dispatchkey_idx_ ||
576	          next_backend_ != rhs.next_backend_ ||
577	          current_backendcomponent_idx_ != rhs.current_backendcomponent_idx_;
578	    }
579	    DispatchKey operator*() const {
580	      auto functionality_key =
581	          static_cast<DispatchKey>(current_dispatchkey_idx_);
582	      if (isPerBackendFunctionalityKey(functionality_key)) {
583	        auto next_key = toRuntimePerBackendFunctionalityKey(
584	            functionality_key,
585	            static_cast<BackendComponent>(current_backendcomponent_idx_));
586	        // We expect all of the Dense, Sparse, Quantized, and Autograd keys to
587	        // be ordered the same way with respect to their backends
588	        TORCH_INTERNAL_ASSERT(
589	            toBackendComponent(next_key) ==
590	                static_cast<BackendComponent>(current_backendcomponent_idx_),
591	            "Tried to map functionality key ",
592	            toString(functionality_key),
593	            " and backend bit ",
594	            toString(
595	                static_cast<BackendComponent>(current_backendcomponent_idx_)),
596	            " to a runtime key, but ended up with ",
597	            toString(next_key),
598	            ". This can happen if the order of the backend dispatch keys in DispatchKey.h isn't consistent.",
599	            " Please double check that enum for inconsistencies.");
600	        return next_key;
601	      } else {
602	        return functionality_key;
603	      }
604	    }
605	
606	   private:
607	    const uint64_t* data_ptr_;
608	    uint8_t next_functionality_;
609	    uint8_t next_backend_;
610	    // These are in an invalid state at construction time, and set by the
611	    // first increment call
612	    uint8_t current_dispatchkey_idx_{end_iter_key_val};
613	    uint8_t current_backendcomponent_idx_{end_iter_key_val};
614	  };
615	
616	 public:
617	  // Returns iterator to the first key in the set. If no keys are in the
618	  // set, then will return the end iterator.
619	  iterator begin() const {
620	    return iterator(&repr_);
621	  }
622	
623	  // We do not need to iterate beyond EndOfFunctionalityKeys so we will treat
624	  // this as the end iterator.
625	  iterator end() const {
626	    return iterator(&repr_, iterator::end_iter_mask_val);
627	  }
628	};
