199	  // If there are no keys, set to end iterator value
200	  if (first_functionality_idx == std::numeric_limits<uint64_t>::max() ||
201	      next_functionality_ == iterator::end_iter_mask_val) {
202	    // Set up state to be the same as end()
203	    next_functionality_ = iterator::end_iter_mask_val;
204	    current_dispatchkey_idx_ = iterator::end_iter_key_val;
205	    next_backend_ = 0;
206	    current_backendcomponent_idx_ = iterator::end_iter_key_val;
207	    return *this;
208	  }
