210	  // The +1 is because of DispatchKey::Undefined and
211	  // BackendComponent::InvalidBit
212	  auto new_next_functionality = first_functionality_idx + 1;
213	  auto new_backendcomponent_idx = first_backendcomponent_idx + 1;
214	  // and the -num_backends is because the first <num_backends> bits in the
215	  // keyset are not Dispatch Keys.
216	  auto next_dispatchkey_idx = new_next_functionality - num_backends;
217	
218	  // If the current functionality bit is a per-backend bit, we need special
219	  // handling
220	  if (isPerBackendFunctionalityKey(
221	          static_cast<DispatchKey>(next_dispatchkey_idx))) {
222	    // case 1: if the current backend is undefined, then there is no valid
223	    // backend instance of this functionality key so we can skip it.
224	    if (first_backendcomponent_idx == std::numeric_limits<uint64_t>::max()) {
225	      // increment the functionality mask so we skip the current functionality
226	      // bit on the next increment.
227	      next_functionality_ = new_next_functionality;
228	      ++(*this);
229	      return *this;
230	    }
231	
232	    // Otherwise, at this point we know what the current backend and
233	    // functionality bits are.
234	    current_dispatchkey_idx_ = next_dispatchkey_idx;
235	    current_backendcomponent_idx_ = new_backendcomponent_idx;
236	
237	    // Next, we need to set up the masks for the next increment.
238	    uint64_t next_backendcomponent_bits =
239	        llvm::maskTrailingZeros<uint64_t>(first_backendcomponent_idx + 1) &
240	        full_backend_mask & *data_ptr_;
241	    uint64_t next_backendcomponent_idx =
242	        llvm::findFirstSet(next_backendcomponent_bits);
243	    if (next_backendcomponent_idx == std::numeric_limits<uint64_t>::max()) {
244	      // case 2: the current backend is valid, but there is not another backend
245	      // in the keyset. In this case, we need to bump the functionality mask and
246	      // reset the backend mask for the next increment
247	      next_functionality_ = new_next_functionality;
248	      next_backend_ = 0;
249	    } else {
250	      // case 3: we have another backend to iterate over. We want to iterate
251	      // over the same functionality bit next time, but a different backend bit.
252	      next_backend_ = first_backendcomponent_idx + 1;
253	    }
254	  } else {
255	    // Functionality bits that aren't per backend are simpler to handle. We can
256	    // ignore the backend bits.
257	    TORCH_INTERNAL_ASSERT(next_backend_ == 0);
258	    current_dispatchkey_idx_ = next_dispatchkey_idx;
259	    next_functionality_ = new_next_functionality;
260	  }
261	  return *this;
